}

/// Production verifier that delegates to GitHub's artifact attestation API.
struct SigstoreAttestationVerifier<'a> {
    owner: &'a str,
    repo_name: &'a str,
    api_url: &'a str,
}

#[async_trait]
impl AttestationVerifier for SigstoreAttestationVerifier<'_> {
    async fn verify_blob(
        &self,
        path: &std::path::Path,
    ) -> std::result::Result<bool, VerificationStatus> {
        match crate::github::sigstore::verify_attestation(
            path,
            self.owner,
            self.repo_name,
            None,
            Some(self.api_url),
        )
        .await
        {
            Ok(v) => Ok(v),
            Err(crate::github::sigstore::AttestationError::NoAttestations) => {
                Err(VerificationStatus::NoAttestations)
            }
            Err(e) => Err(VerificationStatus::Error(e.to_string())),
        }
    }
}

/// Verify GitHub artifact attestations for a downloaded artifact.
///
/// First attempts to verify the archive blob as a whole (the existing,
/// preferred path). If the blob has no attestation and the file is an archive,
/// extracts it and requires every regular file inside to be individually
/// attested. Symlinks, hardlinks, and other non-regular entries are rejected
/// outright rather than treated as covered.
///
/// This is fail-closed: partial coverage or any verification failure is an
/// error. Only a complete successful attestation of the blob or of every
/// regular archive member returns `Ok(true)`.
async fn verify_github_attestations_for_path(
    file_path: &std::path::Path,
    verifier: &dyn AttestationVerifier,
) -> std::result::Result<bool, VerificationStatus> {
    // Try the whole archive/blob first.
    match verifier.verify_blob(file_path).await {
        Ok(true) => return Ok(true),
        Ok(false) => return Ok(false),
        Err(VerificationStatus::NoAttestations) => {}
        Err(e) => return Err(e),
    }

    // Only archives can have individually-attested contents.
    let format = file::TarFormat::from_file_name(
        &file_path.file_name().unwrap_or_default().to_string_lossy(),
    );
    if !format.is_archive() {
        return Err(VerificationStatus::NoAttestations);
    }

    let tmp_dir = match tempfile::tempdir() {
        Ok(d) => d,
        Err(e) => return Err(VerificationStatus::Error(e.to_string())),
    };
    if let Err(e) = file::untar(file_path, tmp_dir.path(), &file::TarOptions::new(format)) {
        return Err(VerificationStatus::Error(e.to_string()));
    }

    let mut found_file = false;
    for entry in WalkDir::new(tmp_dir.path()).follow_links(false) {
        let entry = match entry {
            Ok(e) => e,
            Err(e) => return Err(VerificationStatus::Error(e.to_string())),
        };
        let entry_path = entry.path();
        let file_type = entry.file_type();
        if file_type.is_dir() {
            continue;
        }
        if !file_type.is_file() {
            let rel = entry_path
                .strip_prefix(tmp_dir.path())
                .unwrap_or(entry_path);
            return Err(VerificationStatus::Error(format!(
                "archive contains non-regular entry {} which cannot be attested",
                rel.display()
            )));
        }
        found_file = true;
        match verifier.verify_blob(entry_path).await {
            Ok(true) => continue,
            Ok(false) => {
                let rel = entry_path
                    .strip_prefix(tmp_dir.path())
                    .unwrap_or(entry_path);
                return Err(VerificationStatus::Error(format!(
                    "attestation verification returned false for {}",
                    rel.display()
                )));
            }
            Err(VerificationStatus::NoAttestations) => {
                let rel = entry_path
                    .strip_prefix(tmp_dir.path())
                    .unwrap_or(entry_path);
                return Err(VerificationStatus::Error(format!(
                    "no attestation found for {}",
                    rel.display()
                )));
            }
            Err(e) => return Err(e),
        }
    }

    if !found_file {
        return Err(VerificationStatus::Error(
            "archive contains no regular files to attest".to_string(),
        ));
    }

    Ok(true)
}
